var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 오래 기다리셨습니다!","JPN":"はい、お待たせしました！","ENG":"Now, gather around!","TWN":"來吧，大家久等了！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그러면 카나리아 스쿼드의 코핀 컴퍼니 입사를 기념하면서 다 같이~!","JPN":"それじゃあ、カナリア・スクワッドのコフィンカンパニー入社を記念して、せーの！","ENG":"Then, to celebrate Canary Squad's official recruitment to Coffin Company!","TWN":"慶祝金絲雀小隊加入科芬公司，大家一起來～！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"건배!","JPN":"乾杯！","ENG":"Cheers!","TWN":"乾杯！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"크으, 좋다. 역시 하루의 마무리는 맥주로 해야지.","JPN":"くぅ～いいね。やっぱり一日の終わりにはビールだろ。","ENG":"Ooh, so good. It's always good to end the day with a cold beer.","TWN":"哇！好棒！果然還是必須要用冰涼的啤酒來結束這回合。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"살찌지 않게 적당히 마셔요. 라이카는 체력 단련도 대충 하잖아요.","JPN":"太らないようにほどほどに飲んでよね。ライカは体力訓練も適当なんだから。","ENG":"But don't drink too much or you'll get fat. It's because you slack off when you do training.","TWN":"萊卡，你少喝點，否則會變胖，畢竟你也沒在認真運動。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어휴, 어휴. 꼬맹아. 내가 너 때문에 못 살겠다, 응?","JPN":"はあ、おこちゃま。あんたのせいで私がどれだけ大変かわかってんのか、うん？","ENG":"Oh, come on, kid. Will you get off my back?","TWN":"哎呀呀，臭小鬼。我會被你氣死，嗯？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으윽…. 엉겨붙지 말고 좀 떨어져요.","JPN":"ううっ……くっつかないで離れてよ。","ENG":"Ngh... Please respect my personal space.","TWN":"呃呃……別粘著我，離遠點。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……갑자기 술자리가 열렸네.","JPN":"……いきなり飲み会になったね。","ENG":"...So it's a drinking party now, huh?","TWN":"……突然喝開啦。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"술자리라니. 저녁 식사에 곁들이는 정도지.","JPN":"飲み会だなんて大層な。夕飯にちょっと飲むくらいだよ。","ENG":"A drinking party? No, we're just having a drink to complement our dinner.","TWN":"沒有喝開啦，晚餐時間小酌一杯而已。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 미나도 한 잔 어때?","JPN":"はい、ミナも一杯どう？","ENG":"Here, how about a glass, Mina?","TWN":"來，米娜也喝一杯吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 난 괜찮아. 아직은 학생인걸.","JPN":"あ、私はいいよ。まだ学生だから。","ENG":"Oh, no, thank you. I'm still a student.","TWN":"我不用，我還是學生。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"학생이라고? 정말?","JPN":"学生？　本当に？","ENG":"Really? You're still a student?","TWN":"學生？真的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"짜잔! 여기 주문하셨던 구운 소시지 안주 대령이요!","JPN":"じゃーん！　ご注文の焼きソーセージのおつまみです！","ENG":"Tada! Here are the sausages you ordered!","TWN":"鏘鏘！這是你點的下酒菜烤香腸！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"우와, 윤기가 좌르르 흐르네. 장식에 쓰는 야채까지 제대로 구웠어.","JPN":"うわ、ツヤツヤしてる。デコレーションの野菜までちゃんと焼いたんだね。","ENG":"Wow, they look so good. She even cooked the little decorative vegetables.","TWN":"哇，油油亮亮的，連用來擺盤的蔬菜都烤得香噴噴的。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"호오, 호오……. 하읍.","JPN":"ふう、ふう……はむ。","ENG":"Huu, huu... Nom.","TWN":"呼，呼……嗝。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……맛있다. 편의점에서 파는 싸구려인데.","JPN":"……おいしいわ。コンビニで売ってる安物なのに。","ENG":"...It's good. Even though it's the cheap stuff sold in convenience stores.","TWN":"……真好吃，明明是便利店裡賣的便宜貨。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};